// =========================================================================
// Title: Tie-Dye Sonification (Harmonic Drone)
// Note: Versione ammorbidita. Utilizza intervalli di quinta giusta (110Hz e 165Hz)
// e sottomultipli per una modulazione FM molto più dolce.
// =========================================================================

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f*f*(3.0-2.0*f);

    float a = fract(sin(dot(i, vec2(12.9898, 78.233))) * 43758.5453);
    float b = fract(sin(dot(i + vec2(1.0, 0.0), vec2(12.9898, 78.233))) * 43758.5453);
    float c = fract(sin(dot(i + vec2(0.0, 1.0), vec2(12.9898, 78.233))) * 43758.5453);
    float d = fract(sin(dot(i + vec2(1.0, 1.0), vec2(12.9898, 78.233))) * 43758.5453);
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

vec2 mainSound( int samp, float time ) {
    // Frequenze armoniche: 110Hz (La) e 165Hz (Mi, una quinta giusta sopra)
    float freqL = 110.0; 
    float freqR = 165.0; 

    // Modulazione molto più dolce (usiamo 55.0Hz, che è l'ottava bassa di 110Hz)
    // Questo garantisce che le distorsioni siano intonate con la nota principale
    float t = time * 0.2;
    float modL = sin(6.28318 * 55.0 * time + t) * 0.8; 
    float modR = cos(6.28318 * 55.0 * time - t) * 0.8;

    // Generazione dei toni principali (onde sinusoidali modificate dolcemente)
    float toneL = sin(6.28318 * freqL * time + modL);
    float toneR = sin(6.28318 * freqR * time + modR);

    // Aggiungiamo un'ottava superiore morbida per dare un po' di "luce" al suono
    toneL += sin(6.28318 * 220.0 * time) * 0.25;
    toneR += sin(6.28318 * 330.0 * time) * 0.25;

    // Rumore di fondo abbassato di frequenza e di volume (solo per dare un po' di respiro)
    float nL = noise(vec2(time * 300.0, time * 100.0)) - 0.5;
    float nR = noise(vec2(time * 100.0, time * 320.0)) - 0.5;

    // Mix finale: diamo priorità ai toni armonici e scaliamo tutto per non superare 1.0
    // (evitando così il fastidioso effetto "onda quadra" del clamp)
    vec2 audio = vec2(toneL, toneR) * 0.6 + vec2(nL, nR) * 0.03;

    // Inviluppo per ammorbidire l'attacco iniziale
    float env = smoothstep(0.0, 2.0, time) * (0.8 + 0.2 * sin(time * 0.5));

    return clamp(audio * env, -1.0, 1.0);
}
//SOUND_END
//SOUND_END

// 1. FUNZIONI DI SUPPORTO (Noise & Random)
// Devono essere definite fuori dal main

float random (in vec2 st) {
    return fract(sin(dot(st.xy, vec2(12.9898,78.233))) * 43758.5453123);
}

// Rumore di valore (Value Noise) 2D
float noise (in vec2 st) {
    vec2 i = floor(st);
    vec2 f = fract(st);

    // Interpolazione cubica (Smoothstep) per bordi morbidi
    vec2 u = f * f * (3.0 - 2.0 * f);

    float a = random(i);
    float b = random(i + vec2(1.0, 0.0));
    float c = random(i + vec2(0.0, 1.0));
    float d = random(i + vec2(1.0, 1.0));

    return mix(a, b, u.x) +
            (c - a)* u.y * (1.0 - u.x) +
            (d - b) * u.x * u.y;
}

// 2. MAIN IMAGE (Il tuo motore riconosce questa firma)
void mainImage( out vec4 fragColor, in vec2 fragCoord )
{
    // Calcolo coordinate UV normalizzate (0.0 - 1.0)
    vec2 uv = fragCoord.xy / iResolution.xy;
    float u = uv.x;
    float v = uv.y;

    // --- I TUOI PARAMETRI ORIGINALI ---
    float scale = 4.0;
    int octaves = 5;
    float cloudCover = 0.0; // Prova ad alzare questo (es. 0.1 o 0.2) per sfoltire

    // --- FIX INCOLLATURA (Mirroring) ---
    // Questo crea l'effetto specchio per rendere la texture "tileable"
    float u_fix = abs(u * 2.0 - 1.0);
    float v_fix = abs(v * 2.0 - 1.0);
    vec2 st = vec2(u_fix, v_fix) * scale;

    // --- FBM LOOP (Fractal Brownian Motion) ---
    //  Somma strati di rumore a frequenze crescenti e ampiezze decrescenti
    float value = 0.0;
    float amplitude = 0.5;
    float totalAmplitude = 0.0; // Per normalizzare alla fine

    for (int i = 0; i < 5; i++) {
        // Usiamo un loop fisso (GLSL preferisce) e rompiamo se serve
        if (i >= octaves) break; 

        value += amplitude * noise(st);
        st *= 2.0;       // Lacunarity: Raddoppia la frequenza
        totalAmplitude += amplitude;
        amplitude *= 0.5; // Gain: Dimezza l'ampiezza
    }

    // Normalizziamo il valore tra 0.0 e 1.0
    value /= totalAmplitude;

    // --- CONTRASTO E MASKING ---
    // Definiamo dove sono le nuvole rispetto al cielo vuoto
    float n = smoothstep(cloudCover + 0.2, cloudCover + 0.8, value);

